from Cryptodome.PublicKey import RSA
from Cryptodome.Protocol.KDF import PBKDF2
from Cryptodome.Hash import SHA256
from Cryptodome.Cipher import AES
from Cryptodome.Util.Padding import unpad

# Just create a small list of cipher names
# Normally, this will be a very large password file, like the rockyou list
passwords = [b"vigenere", b"shift", b"one time pad", b"rsa"]

# Option 1: Use function import_key() that raises a ValueError exception if passphrase is incorrect
with open("./Lab 6 - Key Management/mystery.pem", "r") as f:
	data = f.read()

for password in passwords:
	try:
		RSA.import_key(data, password)
		print(f"Password: {password.decode()}")
		break
	except ValueError:
		continue


# Option 2: Use the algorithms and raw data from the PEM file as decoded by the ASN.1 decoder
salt = bytes.fromhex("AE6C62E5EBCF65C8")
iv = bytes.fromhex("B33BBC0126B1684E91FA5B400D189A17")
ct = bytes.fromhex("")
for password in passwords:
	key = PBKDF2(password, salt, dkLen=32, count=2048, hmac_hash_module=SHA256)
	try:
		cipher = AES.new(key, AES.MODE_CBC, iv)
		pt = unpad(cipher.decrypt(ct), AES.block_size)
		print(f"Password: {password.decode()}\n")
		break
	except (ValueError, KeyError):
		continue
